function getHist(){try{return JSON.parse(localStorage.getItem(HIST_KEY))||[];}catch(e){return[];}}
function setHist(v){try{localStorage.setItem(HIST_KEY,JSON.stringify(v||[]));}catch(e){}}
function saveHistory(item){ try{ if(!item||!item.tmdb_id)return; var arr=getHist(); var id='tmdb_'+item.tmdb_id+'_'+item.media_type; arr=arr.filter(function(x){return x.id!==id;}); arr.unshift({id:id,tmdb_id:item.tmdb_id,media_type:item.media_type,name:item.name||item.title||'',poster_url:item.poster_url||'',year:item.year||'',origin_name:item.origin_name||'',time:Date.now()}); if(arr.length>50)arr.slice(0,50); setHist(arr); }catch(e){} }
function lastHistory(){var h=getHist();return h&&h.length?h[0]:null;}
function nStr(s){return String(s||'').toLowerCase().trim().replace(/[^\w\s\u00C0-\u024F\u1E00-\u1EFF]/g,'').replace(/\s+/g,'');}
function pd(n){return(n<10?'0':'')+n;}
