function mkTCPF(item){ var d=tNorm(item); if(!d||!d.tmdb_id)return $('<div></div>'); var bk=d.backdrop_url||d.poster_url||''; var ps=d.poster_url||''; var vote=d.vote||''; var vNum=Number(vote); var vClass=vNum>=7?'high':vNum>=5?'mid':'low'; var typeLabel=d.media_type==='tv'?'TV Series':'Film'; var card=$('<div class="kk-pfc selector"></div>'); var html='<div class="kk-pfc-bg">'+(bk?'<img src="'+bk+'" loading="lazy">':'<div class="kk-pfc-bg-empty"></div>')+'</div>'; html+='<div class="kk-pfc-overlay"></div><div class="kk-pfc-inner">'; html+=ps?'<div class="kk-pfc-poster"><img src="'+ps+'" loading="lazy"></div>':'<div class="kk-pfc-poster kk-pfc-poster--empty"></div>'; html+='<div class="kk-pfc-info"><div class="kk-pfc-badge">'+E(typeLabel)+'</div><div class="kk-pfc-title">'+E(d.name)+'</div>'; if(d.origin_name&&d.origin_name!==d.name)html+='<div class="kk-pfc-origin">'+E(d.origin_name)+'</div>'; html+='<div class="kk-pfc-meta">'; if(d.year)html+='<span class="kk-pfc-year">'+E(d.year)+'</span>'; if(vote)html+='<span class="kk-pfc-vote kk-pfc-vote--'+vClass+'">'+vote+'</span>'; html+='</div></div></div>'; card.html(html); bE(card,function(){ saveHistory(d); Lampa.Activity.push({url:'',title:d.name||'',component:'kkphim_tmdb_detail',tmdb_id:d.tmdb_id,media_type:d.media_type,page:1}); }); return card; }
