function mkHero(bk,ps,logoH,tH,origin,extra){ extra=extra||{}; var posterH=ps?'<img src="'+ps+'" loading="lazy">':''; var originH=''; if(origin&&origin!==(extra._title||''))originH='<div class="kk-hm-origin">'+E(origin)+'</div>'; var html='<div class="kk-hero"><div class="kk-hero-backdrop">'+(bk?'<img src="'+bk+'" loading="lazy">':'<div class="kk-hero-backdrop-empty"></div>')+'</div><div class="kk-hero-card"><div class="kk-hero-poster-wrap"><div class="kk-hero-poster">'+posterH+'</div></div><div class="kk-hero-meta">'; if(extra.year||extra.country){ html+='<div class="kk-hm-yc">'; if(extra.year)html+='<span class="kk-hm-year">'+E(extra.year)+'</span>'; if(extra.country)html+='<span class="kk-hm-country">'+E(extra.country)+'</span>'; html+='</div>'; } html+=(logoH||tH)+originH; if(extra.tagline)html+='<div class="kk-hm-tagline">'+E(extra.tagline)+'</div>'; html+='<div class="kk-hm-badges">'; if(extra.vote)html+='<span class="kk-hm-vote">'+E(extra.vote)+'<small>TMDB</small></span>'; if(extra.status)html+='<span class="kk-hm-badge">'+E(extra.status)+'</span>'; html+='</div>'; if(extra.runtime||extra.genres){ html+='<div class="kk-hm-rtg">'; if(extra.runtime)html+='<span class="kk-hm-rt">'+E(extra.runtime)+'</span>'; if(extra.runtime&&extra.genres)html+='<span class="kk-hm-dot">&#8226;</span>'; if(extra.genres)html+='<span class="kk-hm-genres">'+E(extra.genres)+'</span>'; html+='</div>'; } html+='</div></div></div>'; return $(html); }
